            entity.Property(p => p.CosmosId).ToJsonProperty("id");
            entity.HasKey(p => p.CosmosId);

            // BREAKING CHANGE 3 — HasIndex() now throws for Cosmos provider.
            // Removed: entity.HasIndex(p => p.Sku);
            // Cosmos indexing is managed via the container's indexing policy, not EF.
        });
    }
}

